import random

def play_game():
    secret = random.randint(1, 100)
    attempts = 0
    print("I picked a number between 1 and 100!")

    while True:
        guess_str = input("Your guess: ")
        try:
            guess = int(guess_str)
        except ValueError:
            print("Please enter a number!")
            continue

        attempts += 1

        if guess < secret:
            print("Too low! Try higher.")
        elif guess > secret:
            print("Too high! Try lower.")
        else:
            print(f"Correct! You got it in {attempts} guesses!")
            break

play_game()

